import React from 'react';
import styles from './subscription.module.css';
import Option from './option';

const Subscription: React.FC = () => {
  return (
    <div className={styles.wrapper_subscription}>
        <Option title="One time purchase" />
        <Option title="Subscribe and delivery every " desc="Subscribe now and get the 10% of discount on every recurring order.  The discount will be applied at checkout.< See details" isDropdown={true} />


    </div>
  )
}

export default Subscription;
